import React, { useEffect, useState, useCallback } from 'react';
import { Book, Category } from '../types';
import api from '../utils/api';
import { useAuth } from '../hooks/useAuth';
import Toast from '../components/Toast';

export default function Books() {
  const { user } = useAuth();
  const isStaff = user?.userType === 'user';
  const [books, setBooks] = useState<Book[]>([]);
  const [categories, setCategories] = useState<Category[]>([]);
  const [total, setTotal] = useState(0);
  const [page, setPage] = useState(1);
  const [search, setSearch] = useState('');
  const [catFilter, setCatFilter] = useState('');
  const [loading, setLoading] = useState(true);
  const [modal, setModal] = useState(false);
  const [editing, setEditing] = useState<Book | null>(null);
  const [toast, setToast] = useState<any>(null);
  const [form, setForm] = useState({ title:'', author:'', isbn:'', category_id:'', publisher:'', published_year:'', description:'', total_copies:'1', available_copies:'1', location:'', language:'English', pages:'' });

  const set = (k: string, v: string) => setForm(f => ({ ...f, [k]: v }));

  const load = useCallback(async () => {
    setLoading(true);
    try {
      const { data } = await api.get('/books', { params: { search, category_id: catFilter, page, limit: 12 } });
      setBooks(data.data); setTotal(data.total);
    } finally { setLoading(false); }
  }, [search, catFilter, page]);

  useEffect(() => { load(); }, [load]);
  useEffect(() => { api.get('/categories').then(r => setCategories(r.data.data || [])); }, []);

  const openAdd = () => { setEditing(null); setForm({ title:'', author:'', isbn:'', category_id:'', publisher:'', published_year:'', description:'', total_copies:'1', available_copies:'1', location:'', language:'English', pages:'' }); setModal(true); };
  const openEdit = (b: Book) => { setEditing(b); setForm({ title:b.title, author:b.author, isbn:b.isbn||'', category_id:String(b.category_id||''), publisher:b.publisher||'', published_year:String(b.published_year||''), description:b.description||'', total_copies:String(b.total_copies), available_copies:String(b.available_copies), location:b.location||'', language:b.language||'English', pages:String(b.pages||'') }); setModal(true); };

  const save = async () => {
    try {
      if (editing) { await api.put(`/books/${editing.id}`, form); setToast({ message:'Book updated!', type:'success' }); }
      else { await api.post('/books', form); setToast({ message:'Book added!', type:'success' }); }
      setModal(false); load();
    } catch (e: any) { setToast({ message: e.response?.data?.message || 'Error', type:'error' }); }
  };

  const deleteBook = async (id: number, title: string) => {
    if (!window.confirm(`Delete "${title}"?`)) return;
    try { await api.delete(`/books/${id}`); setToast({ message:'Book deleted', type:'success' }); load(); }
    catch { setToast({ message:'Failed to delete', type:'error' }); }
  };

  const borrowBook = async (book: Book) => {
    try { await api.post('/borrows/request', { book_id: book.id }); setToast({ message:`Borrow request sent for "${book.title}"!`, type:'success' }); load(); }
    catch (e: any) { setToast({ message: e.response?.data?.message || 'Error', type:'error' }); }
  };

  const inp: React.CSSProperties = { width:'100%', padding:'11px 14px', background:'rgba(255,255,255,0.05)', border:'1.5px solid rgba(255,255,255,0.1)', borderRadius:10, fontSize:14, color:'#f0eee8', fontFamily:'inherit', outline:'none', transition:'all .2s', boxSizing:'border-box' };
  const lbl: React.CSSProperties = { display:'block', fontSize:11, fontWeight:700, color:'var(--text-dim)', marginBottom:7, letterSpacing:'1px', textTransform:'uppercase' };

  return (
    <div className="page-enter" style={{ padding:'32px 36px' }}>
      {toast && <Toast message={toast.message} type={toast.type} onClose={()=>setToast(null)} />}

      {/* Header */}
      <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between', marginBottom:28 }}>
        <div>
          <h1 style={{ fontFamily:"'Playfair Display',serif", fontSize:32, fontWeight:700, color:'var(--text)' }}>Books</h1>
          <p style={{ color:'var(--text-dim)', fontSize:13, marginTop:4 }}>{total} books in library</p>
        </div>
        {isStaff && <button className="btn-primary" onClick={openAdd}>+ Add Book</button>}
      </div>

      {/* Filters */}
      <div style={{ display:'flex', gap:12, marginBottom:24 }}>
        <input className="field" style={{ flex:1 }} value={search} onChange={e=>{setSearch(e.target.value);setPage(1);}} placeholder="🔍  Search title, author, ISBN..." />
        <select className="field" style={{ width:180 }} value={catFilter} onChange={e=>{setCatFilter(e.target.value);setPage(1);}}>
          <option value="">All Categories</option>
          {categories.map(c=><option key={c.id} value={c.id}>{c.name}</option>)}
        </select>
      </div>

      {/* Grid */}
      {loading ? (
        <div style={{ display:'flex', justifyContent:'center', padding:80 }}>
          <div style={{ width:36, height:36, border:'3px solid #c9a84c', borderTopColor:'transparent', borderRadius:'50%', animation:'spin 1s linear infinite' }} />
        </div>
      ) : books.length ? (
        <div style={{ display:'grid', gridTemplateColumns:'repeat(auto-fill, minmax(260px, 1fr))', gap:16, marginBottom:28 }}>
          {books.map(b=>(
            <div key={b.id} style={{ background:'var(--bg2)', border:'1px solid var(--border)', borderRadius:16, padding:20, transition:'all .2s', display:'flex', flexDirection:'column' }}
              onMouseEnter={e=>{(e.currentTarget as any).style.borderColor='rgba(201,168,76,0.3)';(e.currentTarget as any).style.transform='translateY(-3px)';(e.currentTarget as any).style.boxShadow='0 12px 32px rgba(0,0,0,0.3)';}}
              onMouseLeave={e=>{(e.currentTarget as any).style.borderColor='rgba(255,255,255,0.07)';(e.currentTarget as any).style.transform='none';(e.currentTarget as any).style.boxShadow='none';}}>
              <div style={{ display:'flex', justifyContent:'space-between', alignItems:'flex-start', marginBottom:14 }}>

                <span style={{ fontSize:11, fontWeight:700, padding:'4px 10px', borderRadius:99, background:b.available_copies>0?'rgba(16,185,129,0.15)':'rgba(239,68,68,0.15)', color:b.available_copies>0?'#34d399':'#f87171' }}>
                  {b.available_copies>0?`${b.available_copies} left`:'Unavailable'}
                </span>
              </div>
              <h3 style={{ fontSize:15, fontWeight:700, color:'var(--text)', marginBottom:4, lineHeight:1.3 }}>{b.title}</h3>
              <p style={{ fontSize:13, color:'var(--text-dim)', marginBottom:8 }}>{b.author}</p>
              {b.category_name && <span style={{ fontSize:11, fontWeight:600, padding:'3px 10px', borderRadius:99, background:'rgba(201,168,76,0.1)', color:'#c9a84c', marginBottom:12, display:'inline-block' }}>{b.category_name}</span>}
              <div style={{ marginTop:'auto', paddingTop:14, borderTop:'1px solid rgba(255,255,255,0.06)', display:'flex', gap:8 }}>
                {isStaff ? (
                  <>
                    <button onClick={()=>openEdit(b)} style={{ flex:1, padding:'8px', background:'rgba(255,255,255,0.06)', color:'var(--text-dim)', border:'1px solid var(--border)', borderRadius:9, fontSize:12, cursor:'pointer', fontFamily:'inherit', transition:'all .2s' }}>✏️ Edit</button>
                    <button onClick={()=>deleteBook(b.id, b.title)} style={{ padding:'8px 12px', background:'rgba(239,68,68,0.1)', color:'#f87171', border:'1px solid rgba(239,68,68,0.2)', borderRadius:9, fontSize:12, cursor:'pointer', fontFamily:'inherit', transition:'all .2s' }}>🗑️</button>
                  </>
                ) : (
                  <button onClick={()=>borrowBook(b)} disabled={b.available_copies<1}
                    style={{ flex:1, padding:'9px', background:b.available_copies>0?'#c9a84c':'rgba(255,255,255,0.05)', color:b.available_copies>0?'#1a1a2e':'rgba(255,255,255,0.2)', border:'none', borderRadius:9, fontSize:13, fontWeight:700, cursor:b.available_copies>0?'pointer':'not-allowed', fontFamily:'inherit', transition:'all .2s' }}>
                    {b.available_copies>0?'Request Borrow':'Unavailable'}
                  </button>
                )}
              </div>
            </div>
          ))}
        </div>
      ) : (
        <div style={{ textAlign:'center', padding:'80px 0', color:'rgba(255,255,255,0.2)' }}>
          <div style={{ fontSize:56, marginBottom:16 }}>📚</div>
          <p style={{ fontSize:16, fontWeight:600, color:'rgba(255,255,255,0.3)' }}>No books found</p>
        </div>
      )}

      {/* Pagination */}
      {Math.ceil(total/12)>1 && (
        <div style={{ display:'flex', alignItems:'center', justifyContent:'center', gap:10 }}>
          <button onClick={()=>setPage(p=>Math.max(1,p-1))} disabled={page===1} className="btn-ghost" style={{ padding:'8px 18px', opacity:page===1?0.4:1 }}>← Prev</button>
          <span style={{ fontSize:13, color:'var(--text-dim)', padding:'0 8px' }}>Page {page} of {Math.ceil(total/12)}</span>
          <button onClick={()=>setPage(p=>Math.min(Math.ceil(total/12),p+1))} disabled={page===Math.ceil(total/12)} className="btn-ghost" style={{ padding:'8px 18px', opacity:page===Math.ceil(total/12)?0.4:1 }}>Next →</button>
        </div>
      )}

      {/* Modal */}
      {modal && (
        <div style={{ position:'fixed', inset:0, background:'rgba(0,0,0,0.7)', backdropFilter:'blur(6px)', zIndex:1000, display:'flex', alignItems:'center', justifyContent:'center', padding:20 }}>
          <div style={{ background:'var(--bg2)', border:'1px solid var(--border2)', borderRadius:22, padding:32, width:'100%', maxWidth:560, maxHeight:'90vh', overflowY:'auto' }}>
            <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:24 }}>
              <h2 style={{ fontFamily:"'Playfair Display',serif", fontSize:22, fontWeight:700, color:'var(--text)' }}>{editing?'Edit Book':'Add Book'}</h2>
              <button onClick={()=>setModal(false)} style={{ background:'rgba(255,255,255,0.08)', border:'none', color:'rgba(255,255,255,0.5)', width:34, height:34, borderRadius:9, cursor:'pointer', fontSize:16 }}>✕</button>
            </div>
            <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:14 }}>
              {[['title','Title *','Book title','1/-1'],['author','Author *','Author name',''],['isbn','ISBN','978-...',''],['category_id','','',''],['publisher','Publisher','Publisher name',''],['published_year','Year','e.g. 2023',''],['total_copies','Total Copies','1',''],['available_copies','Available','1',''],['location','Location','e.g. A1-S1',''],['language','Language','English',''],['pages','Pages','e.g. 320','']].map(([key,label,ph,gc])=>(
                key==='category_id' ? (
                  <div key={key} style={{ gridColumn:gc||undefined }}>
                    <label style={lbl}>Category</label>
                    <select style={{ ...inp, appearance:'none' as any }} value={form.category_id} onChange={e=>set('category_id',e.target.value)}>
                      <option value="">Select category</option>
                      {categories.map(c=><option key={c.id} value={c.id}>{c.name}</option>)}
                    </select>
                  </div>
                ) : (
                  <div key={key} style={{ gridColumn:gc||undefined }}>
                    <label style={lbl}>{label}</label>
                    <input style={inp} value={(form as any)[key]} onChange={e=>set(key,e.target.value)} placeholder={ph} />
                  </div>
                )
              ))}
              <div style={{ gridColumn:'1/-1' }}>
                <label style={lbl}>Description</label>
                <textarea style={{ ...inp, minHeight:80, resize:'vertical' }} value={form.description} onChange={e=>set('description',e.target.value)} placeholder="Book description..." />
              </div>
            </div>
            <div style={{ display:'flex', gap:10, marginTop:22 }}>
              <button onClick={()=>setModal(false)} className="btn-ghost" style={{ flex:1 }}>Cancel</button>
              <button onClick={save} className="btn-primary" style={{ flex:2 }}>{editing?'Update Book':'Add Book'}</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
